(window.webpackJsonp=window.webpackJsonp||[]).push([[125],{752:function(r,n){r.exports="\x3c!-- \r\ntitle: 05-串口通信\r\nsort: \r\n--\x3e \r\n# Arduino串口的使用\r\n\r\n## 初始化\r\n\r\n使用`Serial.begin(speed)`初始化Arduino的串口通信功能。\r\n\r\n## 串口输出\r\n\r\n```c++\r\nSerial.print(val);\r\nSerial.println(val);\r\n```\r\n\r\n## 串口输入\r\n\r\n```cpp\r\nSerial.read();\r\nSerial.available();\t// 返回缓冲区接收到的字节数\r\nif(Serial.available()>0)\r\n  {\r\n    char ch=Serial.read();\r\n    Serial.print(ch);\r\n  }\r\n```\r\n\r\n## 中断\r\n\r\n`attachInterrupt(interrupt, function, mode)`\r\n\r\n1. 中断通道编号\r\n\r\n   > UNO\\Ethernet\t2 3 　 　 　 　\r\n   > Mega2560 \t\t2 3 21 20 19 18\r\n   > Leonardo \t\t\t3 2 0 1 　 　\r\n   > Due 　\t\t\t\t所有IO口均可\r\n   >\r\n   > 0或1对应2，3引脚\r\n\r\n2. function\r\n\r\n   > 处理中断的函数\r\n\r\n3. 中断模式\r\n\r\n   > LOW \t\t\t低电平触发\r\n   >\r\n   > HIGH \t\t\t高电平触发(该中断模式仅适用于Arduino due)\r\n   >\r\n   > CHANGE \t电平变化，高电平变低电平、低电平变高电平\r\n   > RISING \t\t上升沿触发\r\n   > FALLING \t下降沿触发\r\n\r\n"}}]);